export function validateDateMaskedInput(inputVal: string) {
  if (isNullOrUndefinedOrEmptyString(inputVal)) {
    return;
  }
  const date = inputVal.replace(/\D/g, '').match(/(\d{0,2})(\d{0,2})(\d{0,4})/);
  const firstPart = date[1].match(/(\d{0,1})(\d{0,1})/);
  const firstVal = computeFirstPartForDateMask(firstPart);
  const secondPart = date[2].match(/(\d{0,1})(\d{0,1})/);
  const secondVal = computeSecondPartForDateMask(secondPart);
  const thirdPart = date[3].match(/(\d{0,1})(\d{0,1})(\d{0,1})(\d{0,1})/);
  const thirdVal = computeThirdPartForDateMask(thirdPart);
  const totalVal = firstVal + secondVal + thirdVal;
  return dateMaskToString(totalVal);
}

//zipcode validation

export const applyZipcodeMask = (value): string => {
  if (isNullOrUndefinedOrEmptyString(value)) {
    return;
  }
  const zipCode = value.replace(/\D/g, '').match(/\d{0,5}/);
  return computeMaskForZipCode(zipCode[0]);
};

export function computeMaskForZipCode(zipcode: string) {
  let zipValue;
  if (zipcode.length < 5) {
    zipValue = zipcode;
    return zipValue;
  }
  return zipcode;
}

export function validateZipcodeMaskedInput(inputVal: string) {
  return inputVal.replace(/\D/g, '');
}

