export function uppercaseFirstLetter(text: string) {
  return text.replace(/(^\w)|\s(\w)/g, (match) => match.toUpperCase());
}

async function closeDropdownInZg(zgNearby: ZSoft.ZingGrid, tagName: 'mx-single-select' | 'mx-multi-select') {
  const dropdown = Array.from(zgNearby.getElementsByTagName(tagName));
  // Use for...of instead of callbacks to get await to work properly.
  for (const singleSelect of dropdown) {
    await singleSelect.toggleDropdown(false);
  }
}

type HTMLSelectElement = HTMLMxMultiSelectElement | HTMLMxMultiSelectV2Element | HTMLMxSingleSelectElement;

/** Closes all single and multi-select dropdowns located inside of ZingGrid. */
export async function closeAllDropdownsInZG(hostEl: HTMLSelectElement) {
  // If this is used inside of ZingGrid, we need to close all other dropdowns before opening this one.
  const zgNearby = hostEl.closest('zing-grid');
  if (!isNullOrUndefined(zgNearby)) {
    await closeDropdownInZg(zgNearby, 'mx-single-select');
    await closeDropdownInZg(zgNearby, 'mx-multi-select');
  }
}

export const parseObjectSilent = (input: string): any => {
  if (isNullOrUndefinedOrEmptyString(input)) {
    return {};
  }

  try {
    input = input.replaceAll('\'', '"');
    return JSON.parse(input);
  } catch (e) {
    console.error(e);
    return {};
  }
};

export const iconPrefixElement = (prefixElement: string | PrefixElement) => {
  const iconName = typeof prefixElement === 'string' ? prefixElement : prefixElement.name;
  const iconClass = typeof prefixElement === 'string' ? '' : prefixElement.className;

  // Adding a basic check to ensure prefixElement is valid
  if(isValidKdsIconElementName(iconName) ) {
    return h(iconName, { class: { [iconClass]: true, 'mr-8 mx-label-icon': true } });
  } else {
    return;
  }
};

// Helper: checks to see if the tag is likely a kds-icon-tag
export function isValidKdsIconElementName(name: string): boolean {
  // Needs to fit the kds-icon- format or atleast not have any spaces so it could be a tag name
  // Note: the at least not have "space" in the name was to maintain backwards compatibility with some functionality
  // in regard to the single select.
  return typeof name === 'string' && (name.includes('kds-icon-') || !name.includes(' '))
      && !isNullOrUndefinedOrEmptyString(name);
}

export const findMatchedItem = (item: TreeMenuItem | string, searchText: string) => {
  const searchLower = searchText.toLowerCase();

  if (typeof item === 'string') {
    if (item.toLowerCase().includes(searchLower)) {
      return item;
    }
    return null;
  }

  // Check if the current item label matches the search text
  if (item.label.toLowerCase().includes(searchLower)) {
    return item;
  }

  // If the item has children, search recursively
  if (item.children) {
    const matchedChildren = item.children.map((child: TreeMenuItem) => findMatchedItem(child, searchText))
      .filter((child: TreeMenuItem) => child !== null);

    // If any children match, return a new item with only the matched children
    if (matchedChildren.length > 0) {
      return {
        ...item,
        children: matchedChildren
      };
    }
  }

  // Return null if no match is found
  return null;
};

