export const removeSingleQuotes = (value: string): string => {
  if (value != null) {
    if (value.startsWith('\'')) {
      value = value.substring(1);
    }
    if (value.endsWith('\'')) {
      value = value.substring(0, value.length - 1);
    }
  }
  return value;
};
