import {
  Component,
  Prop,
  Element,
  State,
  Event,
  EventEmitter,
  Host,
  h,
  forceUpdate,
  Method,
  Listen
} from '@stencil/core';
import { wrappingModulus } from '@src/utils/kds-utils/numberUtils';
import { generateUniqueString } from '@src/utils/kds-utils/generateUniqueString';
import {isNullOrUndefined} from "@src/utils/mx-utils/utils";

@Component({
  tag: 'kds-tabs',
  styleUrl: 'kds-tabs.css',
  shadow: false
})
export class KdsTabs {
  uniqueId: string = generateUniqueString();

  @Element() hostEl: HTMLKdsTabsElement;
  /** Sets class(es) on tab container. */
  @Prop() readonly tabsClass: string;

  /** Sets the Style to "card" mode. */
  @Prop() readonly cardMode: boolean = false;

  /** Sets class(es) on content container. */
  @Prop() readonly contentClass: string;
  /** Defines default selected tab. */
  @Prop() readonly defaultSelected: number = 0;
/** Enables or disables tab drag-and-drop. */
  @Prop() readonly isDraggable: boolean = true;
  /** Emits when tabs are changed. Event `detail` contains ID of newly selected tab. */
  @Event() tabChange: EventEmitter<string>;
  /** Emits when tabs are reordered. Event `detail` contains array of IDs of reordered tabs. */
  @Event() reorderTabs: EventEmitter<string[]>;

  /** Emits when tabs load Event `detail` contains array of IDs of initial tab state. */
  @Event() tabsLoaded: EventEmitter<string[]>;

  tabContainer: any;
  draggedTab: any;
  placeholderTab: any;
  startX: number = null;
  startY: number = null;

  // This controls the amount of "drag" the tabs will tolerate before it no longer considers the mousemove a click
  threshold = 5;

  private tabEls: any = { tab: [], content: [] };
  @State() selectedIndex: number;

  private childObserver: MutationObserver = new MutationObserver(() => {
        this.update()
  });

  disconnectedCallback() {
    this.childObserver?.disconnect();
  }

  private dragstart: (index, event) => void;

  @Method()
  /** Manually triggers a re-render. */
  async update() {
    forceUpdate(this);
  }

  componentWillLoad() {
    this.selectedIndex = this.defaultSelected;

    this.childObserver.observe(this.hostEl, { childList: true });

    this.placeholderTab = document.createElement('div');
  }


  componentDidLoad() {
    // Get a list of the current state of tab container
    let IDs = Array.from(this.tabContainer?.children).map((tab: HTMLElement) => tab.id);

    this.tabsLoaded.emit(IDs);
  }

  handleKeyDown(event) {

    switch (event.key) {
      case 'Up':
      case 'Left':
      case 'ArrowUp':
      case 'ArrowLeft':
        event.preventDefault();
        let nonDisabledNextLeft = this.findNonDisabledIndex(this.selectedIndex, "left");
        if(nonDisabledNextLeft != -1)
          this.selectIndex(nonDisabledNextLeft);
        break;
      case 'Down':
      case 'Right':
      case 'ArrowDown':
      case 'ArrowRight':
        event.preventDefault();
        let nonDisabledNextRight = this.findNonDisabledIndex(this.selectedIndex, "right");
        if(nonDisabledNextRight != -1)
          this.selectIndex(nonDisabledNextRight);
        break;
      case 'Home':
        event.preventDefault();
        let nonDisabledHomeIndex = this.findNonDisabledIndex(0, "first");
        // Ensure The intended Tab is not disabled
        if(nonDisabledHomeIndex != -1)
          this.selectIndex(nonDisabledHomeIndex);
        break;
      case 'End':
        event.preventDefault();
        // Ensure The intended Tab is not disabled
        let nonDisabledEndIndex = this.findNonDisabledIndex(0, "last");
        if(nonDisabledEndIndex != -1)
          this.selectIndex(nonDisabledEndIndex);
        break;
    }
  }

  private findNonDisabledIndex(startingIndex: number, direction: 'left' | 'right' | 'first' | 'last'): number {
    let foundIndex = -1;

    switch (direction) {
      case 'left': {
        let index = startingIndex - 1;
        while (this.tabContainer.children[index] !== this.tabContainer.children[startingIndex]) {
          index = wrappingModulus(index, this.tabContainer.children.length);
          if (this.tabContainer.children[index].getAttribute("disabled") == null) {
            foundIndex = index;
            break;
          }
          index--;
        }
        break;
      }
      case 'right': {
        let index = startingIndex + 1;
        while (this.tabContainer.children[index] !== this.tabContainer.children[startingIndex]) {
          index = wrappingModulus(index, this.tabContainer.children.length);
          if (this.tabContainer.children[index].getAttribute("disabled") == null) {
            foundIndex = index;
            break;
          }
          index++;
        }
        break;
      }
      case 'first': {
        for (let index = 0; index < this.tabContainer.children.length; index++) {
          if (this.tabContainer.children[index].getAttribute("disabled") == null) {
            foundIndex = index;
            break;
          }
        }
        break;
      }
      case 'last': {
        for (let index = this.tabContainer.children.length - 1; index >= 0; index--) {
          if (this.tabContainer.children[index].getAttribute("disabled") == null) {
            foundIndex = index;
            break;
          }
        }
        break;
      }
    }

    return foundIndex;
  }

  /** Sets and focuses the selected tab to the given index.
   * @index The index of the tab to be selected.
   */
  async selectIndex(index: number) {
    const newIndex = wrappingModulus(index, this.tabContainer.children.length);
    this.selectByIndex(newIndex);
  }


  /** Sets and focuses the selected tab to the given uniqueID (found on the tab's button ID).
   */
  @Method()
  async selectTab(unqueID: string) {
    const tabIndex = Array.from(this.tabContainer?.children).findIndex((tab: HTMLElement) => {return tab.id == unqueID});
    this.selectByIndex(tabIndex);
  }

  private selectByIndex(tabIndex: number) {
    if (tabIndex == -1 || isNullOrUndefined(tabIndex) || isNullOrUndefined(tabIndex) || tabIndex === this.selectedIndex) {
      return;
    }

    // Check if the tab button is disabled
    if (this.tabContainer.children[tabIndex].getAttribute("disabled") != null) {
      return;
    }

    this.selectedIndex = tabIndex;
    this.tabContainer.children[this.selectedIndex].closest('.kds-Tabs-tab').focus();
    this.tabChange.emit(this.tabContainer.children[this.selectedIndex].closest('.kds-Tabs-tab').id);
  }

  getDragAfterElement(container, x) {
    const draggableElements = [...container.querySelectorAll('button:not(.dragging)')];
    return draggableElements.reduce((closest, child) => {
      const box = child.getBoundingClientRect();
      const offset = x - box.left - box.width / 2;
      if (offset < 0 && offset > closest.offset) {
        return { offset: offset, element: child };
      } else {
        return closest;
      }
    }, { offset: Number.NEGATIVE_INFINITY }).element;
  }

  @Listen('mouseup', { target: 'document' })
  async dragend(event) {
    if (!this.isDraggable) return;
    // Ignore all this code if this ends up being a "click"?
    if (!this.isClick(event) && this.draggedTab && this.draggedTab.classList.contains("dragging")) {
      let existingPlaceholder = document.getElementById('placeholderTab');

      if (existingPlaceholder)
        this.tabContainer.removeChild(existingPlaceholder);
      const afterElement = this.getDragAfterElement(this.tabContainer, event.clientX);

      if (afterElement == null) {
        this.tabContainer.appendChild(this.draggedTab);
      } else {
        this.tabContainer.insertBefore(this.draggedTab, afterElement);
      }

      // Selected index is now the new position in the tab container
      let draggedTabIndex =  Array.from(this.tabContainer?.children).indexOf(this.draggedTab);

      this.selectedIndex = draggedTabIndex;

      this.draggedTab.style.display = "flex";
      this.draggedTab?.classList?.remove('dragging');
      this.draggedTab = null;

      // Get a list of the current state of tab container
      let IDs = Array.from(this.tabContainer?.children).map((tab: HTMLElement) => tab.id);

      this.reorderTabs.emit(IDs);
    }
    this.startX = null;
    this.startY = null;
  }


  @Listen('mousemove', { target: 'document' })
  dragover(event) {
      if (!this.isDraggable) return;
    // Check if not "clicking"
    if (!this.isClick(event)) {
      if (this.draggedTab && this.draggedTab.classList.contains("dragging") && !this.draggedTab.disabled) {

        // Remove existing placeholder and swap in a new one based off new mouse position
        this.placeholderTab.remove()

        const afterElement = this.getDragAfterElement(this.tabContainer, event.clientX);

        let xCenter = event.clientX - (this.draggedTab.offsetWidth / 2);

        // stop tab from leaving tab container
        if (xCenter > this.tabContainer.getBoundingClientRect().left && xCenter < (this.tabContainer.getBoundingClientRect().right - this.draggedTab.offsetWidth))
          this.draggedTab.style.left = xCenter + "px";

        this.draggedTab.style.top = this.tabContainer.getBoundingClientRect().top + window.visualViewport.pageTop - 10 + "px"

        this.placeholderTab.style.width = this.draggedTab.offsetWidth + "px";
        this.placeholderTab.style.marginRight = "8px";
        this.placeholderTab.id = "placeholderTab";

        // insert placeholder to create gap
        if (afterElement == null) {
          this.tabContainer.appendChild(this.placeholderTab);
        } else {
          this.tabContainer.insertBefore(this.placeholderTab, afterElement);
        }
      } else if (this.startX != null && this.startY != null) {
        // start dragging if you haven't started already
        this.draggedTab = event.target.closest('.kds-Tabs-tab');

        if (this.draggedTab && !this.draggedTab.disabled) {
          this.draggedTab?.classList?.add('dragging');
          let xCenter = event.clientX - (this.draggedTab.offsetWidth / 2);
          this.draggedTab.style.left = xCenter + "px";
          this.draggedTab.style.top = this.tabContainer.getBoundingClientRect().top + window.visualViewport.pageTop - 10 + "px";
        }

      }
    }
  }

  isClick(event) {
    let isClick = false;
    let diffX = Math.abs(event.clientX - this.startX);
    let diffY = Math.abs(event.clientY - this.startY);

    if (diffX < this.threshold && diffY < this.threshold)
      isClick = true;

    return isClick;
  }

  render() {

    const newTabs = Array.from(this.hostEl.children).reduce(
        (acc, el) => {
          const slot = el.getAttribute('slot') as string;
          ('tab' === slot || 'content' === slot) && acc[slot].push(el);
          return acc;
        },
        { tab: [], content: [] }
    );

    this.tabEls = {
      tab: [...this.tabEls.tab, ...newTabs.tab],
      content: [...this.tabEls.content, ...newTabs.content]
    };

    this.tabEls.content.forEach((content, contentIndex) => {
      content.setAttribute('slot', `content-${contentIndex}`);
    });

    this.tabEls.tab.forEach((tab, tabIndex) => {
      tab.setAttribute('slot', `tab-${tabIndex}`);
    });

    this.dragstart = async function ( event) {
      let draggedTab = event.target.closest('.kds-Tabs-tab');
      let draggedTabIndex =  Array.from(this.tabContainer?.children).indexOf(draggedTab);

      await this.selectIndex(draggedTabIndex);

      // Needed to determine if this is a click or a drag
      this.startX = event.clientX;
      this.startY = event.clientY;

    }

    return (
      <Host>
        <div
          role='tablist'
          class={{
            'kds-Tabs': true,
            'card-mode': this.cardMode,
            [this.tabsClass]: Boolean(this.tabsClass)
          }}
          ref={(el) => (this.tabContainer = el)}
          onKeyDown={this.handleKeyDown.bind(this)}
        >

       {this.tabEls.tab.map((_, index) => (
  <button
    onMouseDown={ this.isDraggable ? this.dragstart.bind(this) : undefined }
    onClick={ !this.isDraggable ? () => { this.selectByIndex(index) } : undefined }
    id={`Tabs-tab-${this.uniqueId}-${index}`}
    key={index}
    role='tab'
    tabIndex={
      this.tabContainer != undefined &&
      index.toString() === this.tabContainer?.children[this.selectedIndex].getAttribute('id').split('-')[3]
        ? 0
        : -1
    }
    aria-selected={
      this.tabContainer != undefined &&
      index.toString() === this.tabContainer?.children[this.selectedIndex].getAttribute('id').split('-')[3]
        ? 'true'
        : 'false'
    }
    disabled={_.getAttribute('disabled') == 'true'}
    class={{
      'kds-Tabs-tab': true,
      'card-mode': this.cardMode,
      'no-drag': !this.isDraggable,
      selected:
        this.tabContainer != undefined &&
        index.toString() === this.tabContainer?.children[this.selectedIndex].getAttribute('id').split('-')[3]
    }}
  >
    <div class="tabs-inner-wrapper">
      <span
        class="kds-Tab-icon-container"
        style={{ display: this.isDraggable ? 'inline-block' : 'none' }}
      >
        <kds-icon-draggable class="kds-Tab-drag-icon" size="xs" />
      </span>
      <div class="kds-tab-name">
        <slot name={`tab-${index}`} />
      </div>
    </div>
  </button>
))}
        </div>
        {this.tabEls.content.map((_, index) => (
          <section
            id={`Tabs-content-${this.uniqueId}-${index}`}
            key={index}
            role='tabpanel'
            tabIndex={0}
            aria-labelledby={`Tabs-tab-${this.uniqueId}-${index}`}
            hidden={ this.tabContainer == undefined || index.toString() !== this.tabContainer?.children[this.selectedIndex].getAttribute('id').split('-')[3]}
            class={{
              'kds-Tabs-content': true,
              [this.contentClass]: Boolean(this.contentClass)
            }}
          >
            <slot name={`content-${index}`} />
          </section>
        ))}
      </Host>
    );
  }
}
